package org.apache.commons.math3.distribution;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.distribution.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.distribution.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.distribution.HypergeometricDistribution;
import static org.junit.Assert.*;

import java.util.ArrayList;
import java.util.List;

public class StepDefs {

    private HypergeometricDistribution distribution;
    private int[] sampledValues;
    private double cumulativeProbability;

    @Given("a Hypergeometric distribution with populationSize={int}, numberOfSuccesses={int}, and sampleSize={int}")
    public void a_hypergeometric_distribution_with_parameters(int populationSize, int numberOfSuccesses, int sampleSize) {
        try {
            distribution = new HypergeometricDistribution(populationSize, numberOfSuccesses, sampleSize);
        } catch (Exception e) {
            // Handle any exceptions that may occur during creation
            System.out.println("Exception during distribution creation: " + e.getMessage());
        }
    }

    @Given("a Hypergeometric distribution with any valid parameters populationSize=N, numberOfSuccesses=m, and sampleSize=n")
    public void a_hypergeometric_distribution_with_valid_parameters() {
        // This step will use the distribution created in previous step
    }

    @Given("a Hypergeometric distribution with large parameter values where populationSize={int}, numberOfSuccesses={int}, and sampleSize={int}")
    public void a_hypergeometric_distribution_with_large_parameters(int populationSize, int numberOfSuccesses, int sampleSize) {
        try {
            distribution = new HypergeometricDistribution(populationSize, numberOfSuccesses, sampleSize);
        } catch (Exception e) {
            // Handle any exceptions during creation with large parameters
            System.out.println("Exception during distribution creation with large parameters: " + e.getMessage());
        }
    }

    @When("I sample {int} values from the distribution")
    public void i_sample_values_from_the_distribution(int count) {
        try {
            sampledValues = new int[count];
            for (int i = 0; i < count; i++) {
                sampledValues[i] = distribution.sample();
            }
        } catch (Exception e) {
            // Handle sampling exceptions
            System.out.println("Exception during sampling: " + e.getMessage());
        }
    }

    @When("I sample a value from the distribution")
    public void i_sample_a_value_from_the_distribution() {
        try {
            int singleSample = distribution.sample();
            sampledValues = new int[]{singleSample};
        } catch (Exception e) {
            // Handle sampling exceptions
            System.out.println("Exception during single sampling: " + e.getMessage());
        }
    }

    @When("I compute cumulative probabilities")
    public void i_compute_cumulative_probabilities() {
        try {
            // Compute cumulative probability for a reasonable value
            int x = Math.min(distribution.getNumberOfSuccesses(), distribution.getSampleSize()) / 2;
            cumulativeProbability = distribution.cumulativeProbability(x);
        } catch (Exception e) {
            // Handle probability computation exceptions
            System.out.println("Exception during cumulative probability computation: " + e.getMessage());
        }
    }

    @Then("all sampled values should be greater than or equal to {int}")
    public void all_sampled_values_should_be_greater_than_or_equal_to(int minValue) {
        assertNotNull("Sampled values should not be null", sampledValues);
        for (int value : sampledValues) {
            assertTrue("Sampled value " + value + " should be >= " + minValue, value >= minValue);
        }
    }

    @Then("all sampled values should be less than or equal to {int}")
    public void all_sampled_values_should_be_less_than_or_equal_to(int maxValue) {
        assertNotNull("Sampled values should not be null", sampledValues);
        for (int value : sampledValues) {
            assertTrue("Sampled value " + value + " should be <= " + maxValue, value <= maxValue);
        }
    }

    @Then("the sampled value should be greater than or equal to max({int}, n + m - N)")
    public void the_sampled_value_should_be_greater_than_or_equal_to_max(int zero, int minCalculatedValue) {
        assertNotNull("Sampled values should not be null", sampledValues);
        for (int value : sampledValues) {
            int expectedMin = Math.max(zero, minCalculatedValue);
            assertTrue("Sampled value " + value + " should be >= " + expectedMin, value >= expectedMin);
        }
    }

    @Then("the sampled value should be less than or equal to min(m, n)")
    public void the_sampled_value_should_be_less_than_or_equal_to_min(int maxCalculatedValue) {
        assertNotNull("Sampled values should not be null", sampledValues);
        for (int value : sampledValues) {
            assertTrue("Sampled value " + value + " should be <= " + maxCalculatedValue, value <= maxCalculatedValue);
        }
    }

    @Then("the calculations should handle floating-point precision appropriately without returning NaN or incorrect values")
    public void the_calculations_should_handle_floating_point_precision_appropriately() {
        assertFalse("Cumulative probability should not be NaN", Double.isNaN(cumulativeProbability));
        assertTrue("Cumulative probability should be between 0 and 1", cumulativeProbability >= 0.0 && cumulativeProbability <= 1.0);
    }
}

